import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 手勢, 指寬 } from '../bujian/zhi.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
// 執蓮開瓣之臂：左持未敷蓮右開其一瓣——金剛界金剛法與胎藏觀自在同此正統相
export const 執蓮開瓣之臂 = (bi, 筆) => {
    const { M, C, Qk, S, 骨, 衣, 細, 逸, 陰, 陽 } = 筆;
    骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
    // 蕾之蔽：蓮在瓔前——先鑿其身，胸瓔之線斷於蕾後
    {
        const { ctx, u, Y } = bi;
        ctx.save();
        ctx.globalCompositeOperation = 'destination-out';
        ctx.beginPath();
        ctx.moveTo(1.15 * u, Y(30.6));
        ctx.bezierCurveTo(0.9 * u, Y(28.6), 1.2 * u, Y(27.4), 2.35 * u, Y(27.0));
        ctx.bezierCurveTo(3.4 * u, Y(26.9), 4.5 * u, Y(28.6), 4.4 * u, Y(30.4));
        ctx.bezierCurveTo(4.3 * u, Y(31.9), 3.0 * u, Y(32.6), 2.6 * u, Y(32.5));
        ctx.closePath();
        ctx.fill();
        ctx.restore();
    }
    // 未敷蓮：莖自尊左拳上出，蕾傾向尊右（面前）；蕾尖裂一線（將開之機）
    衣(() => {
        M(3.9, 41.8);
        C(3.4, 38.6, 2.9, 35.4, 2.3, 32.4);
        S();
        M(4.6, 41.7);
        C(4.15, 38.6, 3.7, 35.4, 3.1, 32.3);
        S();
        // 蕾：未敷之苞，尖上而微俯（三瓣相裹）
        M(2.0, 32.2);
        C(1.0, 30.8, 1.1, 28.7, 2.35, 27.35);
        S();
        M(3.4, 32.15);
        C(4.55, 30.9, 4.6, 28.9, 3.4, 27.5);
        S();
        M(2.35, 27.35);
        Qk(2.9, 26.9, 3.4, 27.5);
        S();
        細(() => {
            M(2.5, 31.6);
            C(2.3, 30.2, 2.5, 28.9, 2.95, 27.9);
            S();
            M(3.25, 31.5);
            Qk(3.5, 29.9, 3.3, 28.5);
            S();
        });
        // 萼：蕾根兩葉
        逸(() => {
            M(2.05, 31.9);
            Qk(1.5, 32.7, 1.75, 33.6);
            S();
            M(3.35, 31.85);
            Qk(3.9, 32.6, 3.7, 33.5);
            S();
        });
    });
    // 尊左臂：前臂橫入，拳執莖（蔽法自斷莖線）
    骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [6.4, 41.9], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.35, 肘帽: true })));
    側拳(bi, 4.3, 41.6, -0.25, 1.08, -1);
    // 尊右臂：前臂上舉，手向蕾作開瓣之勢——拇與頭指將拈，餘指微張
    骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-4.9, 33.9], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
    {
        const s = 手勢(bi, -3.4, 32.0, 1.0);
        // 掌背小丘（腕承前臂）
        s.衣(() => { s.M(-1.7, 1.6); s.Qk(-0.6, 2.15, 0.6, 1.9); s.S(); });
        s.衣(() => {
            // 頭指與拇指：向蕾相就（將拈一瓣）
            const 頭 = s.指(0.35, 1.3, -Math.PI / 2 + 0.5, [1.7, 1.25, 0.9], [0, 0.22, 0.3]);
            s.畫(頭, 指寬.根, 指寬.梢, { 紋: true });
            const 拇 = s.指(-0.9, 1.5, -Math.PI / 2 + 1.05, [1.5, 1.2], [0, -0.28]);
            s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true });
            // 餘三指：微張而斂
            for (const [i, 根a] of [1.05, 1.6, 2.05].entries()) {
                const 鏈 = s.指(根a, 1.15 - i * 0.12, -Math.PI / 2 + 0.62 + i * 0.16, [1.45 - i * 0.18, 1.05 - i * 0.12], [0, 0.34]);
                s.畫(鏈, 指寬.小根, 指寬.小梢, { 紋: true });
            }
        });
    }
    // 嚴
    臂釧(bi, -1, 12.1, 14.5, 33.4);
    臂釧(bi, 1, 12.1, 14.5, 33.4);
    細(() => {
        腕釧(bi, [[-6.3, 33.2, -5.5, 34.1, -4.7, 34.9], [-5.8, 32.6, -5.0, 33.5, -4.2, 34.3]], [-5.3, 33.6]);
        腕釧(bi, [[7.4, 40.8, 6.9, 41.9, 7.4, 43.1], [8.3, 41.0, 7.8, 42.1, 8.3, 43.3]], [8.0, 42.1]);
    });
};
export const 金剛法 = (bi) => 菩薩坐身(bi, {
    胸瓔滴z: 30.2,
    嚴先: true,
    臂: 執蓮開瓣之臂,
});
